        let shuffled = [...dirs];
        for (let i = shuffled.length - 1; i > 0; i--) {
            const j = Math.floor(rng() * (i + 1));
            [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
        }
        this.dirOrder = shuffled;

        this.visualX = spawnR; 
        this.visualY = spawnC;
        this.rng = rng; // Store RNG for deterministic movement choice
    }

    move() {
        if(this.finishTick !== null) return false; 

        let currentWalls = this.walls[this.r][this.c];
        let candidates = [];
        const dirsMap = {n:{dr:-1,dc:0}, e:{dr:0,dc:1}, s:{dr:1,dc:0}, w:{dr:0,dc:-1}};

        for(let dir of this.dirOrder) {
            let d = dirsMap[dir];
            let nr = this.r + d.dr;
            let nc = this.c + d.dc;

            if(nr >= 0 && nr < this.walls.length && nc >= 0 && nc < this.walls[0].length) {
                let blocked = false;
                if(dir === 'n' && currentWalls.n) blocked = true;
                if(dir === 'e' && currentWalls.e) blocked = true;
                if(dir === 's' && currentWalls.s) blocked = true;
                if(dir === 'w' && currentWalls.w) blocked = true;

                if(!blocked) {
                    let isVisited = false;
                    for(let p of this.path) {
                        if(p.r === nr && p.c === nc) {
                            isVisited = true;
                            break;
                        }
                    }
                    if(!isVisited) {
                        candidates.push({r: nr, c: nc, dir: dir});
                    }
                }
            }
        }

        if(candidates.length > 0) {
            let next = candidates[Math.floor(this.rng() * candidates.length)];
            this.path.push(next);
            this.r = next.r;
            this.c = next.c;

            if(this.r === this.exitR && this.c === this.exitC) {
                this.finishTick = 0; 
                return true;
            }
        } else {
            if(this.path.length > 1) {
                this.path.pop();
                let prev = this.path[this.path.length - 1];
                this.r = prev.r;
                this.c = prev.c;
                this.deadEnds.add(`${this.r},${this.c}`);
            }
        }

        return false;
    }
}

